// Vitest port of the canonical lago-auth `verify_jwt` integration
// suite at `crates/lago/lago-auth/tests/verify_jwt.rs` (broomva/core/life
// commit `944f2ba9`).
//
// JWTs in this file are NOT generated by JavaScript — they were emitted
// by the Rust signer using the same master-seeds + `EcdsaP256Identity`
// the canonical test suite uses (`MasterSeed::from_bytes([N; 32])` →
// `derive_p256_key` → `EcdsaP256Identity::from_key_bytes` →
// `sign_agent_jwt`). The extracted byte-for-byte JWTs below let us
// verify the TypeScript port against the exact same wire payloads the
// Rust verifier accepts/rejects. See the PR body for the extractor
// command + commit SHA.
//
// File under test: ../verify-jwt.ts

import { describe, expect, it, vi } from "vitest";

vi.mock("server-only", () => ({}));

import { JwtError, verifyJwt } from "../verify-jwt";
import {
  type DidRotation,
  EmptyJournal,
  type JournalResolver,
  type RotationChainQuery,
} from "../rotation-chain";

// ---------------------------------------------------------------------------
// Test vectors (extracted from the canonical Rust signer — DO NOT EDIT)
//
// To regenerate: see /tmp/derive-keys/main.rs in the PR body, run
// `cargo run --release` against anima-identity v0.3.0.
// ---------------------------------------------------------------------------

